using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change 1: EF Core 9 renamed the discriminator property
            // from "Discriminator" to "$type". Preserve the old name so existing
            // documents and raw SQL (WHERE c.Discriminator = 'Blog') keep working.
            b.HasDiscriminator<string>("Discriminator")
                .HasValue<Blog>("Blog");

            // Breaking change 2: EF Core 9 maps the CLR key directly to the JSON
            // "id" property. Previously EF synthesised id as "Blog|{key}". Use a
            // value converter to keep the old format for existing documents.
            b.Property(e => e.Id)
                .HasConversion(
                    v => $"Blog|{v}",
                    v => v.StartsWith("Blog|") ? v.Substring("Blog|".Length) : v
                );

            // Breaking change 3: HasIndex now throws – Cosmos doesn't support
            // indexes in the relational sense. EF 8 silently ignored this; EF 9
            // raises InvalidOperationException. Line removed.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

